吹笛柁樓前。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00558","source_record_id":"CN-NT-CAT-00141","alias_record_ids":["CN-NT-CAT-00141"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%88%9F%E4%B8%AD_(%E5%BE%90%E7%85%A7)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-song-5f90-7167', 0, '途中', NULL, '五言律詩', 5, '隻影微陽外，
