)
INSERT INTO poems (
  poet_id, poem_no, volume, title_zh, title_ko, category, meter, body_zh,
  is_notable, status, quality, review_memo
)
SELECT
  p.id,
  COALESCE(existing_poem_count.max_poem_no, 0)
    + row_number() OVER (PARTITION BY p.id ORDER BY ip.title_zh, ip.body_zh)::integer,
  ip.volume::integer, ip.title_zh, ip.title_ko, ip.category, ip.meter::integer, ip.body_zh,
  TRUE, ip.status, ip.quality, ip.review_memo
FROM input_poems ip
JOIN poets p ON p.title_id = ip.poet_slug
LEFT JOIN LATERAL (
  SELECT max(poem_no) AS max_poem_no
  FROM poems
  WHERE poet_id = p.id
) existing_poem_count ON TRUE
WHERE NOT EXISTS (
  SELECT 1
  FROM poems existing
  WHERE existing.poet_id = p.id
    AND existing.title_zh = ip.title_zh
    AND existing.body_zh = ip.body_zh
);

UPDATE poets p
SET poem_count = sub.cnt
FROM (
  SELECT poet_id, count(*)::integer AS cnt
  FROM poems
  WHERE poet_id IN (SELECT id FROM poets WHERE title_id IN ('candidate-song-7a0b-9865', 'candidate-song-694a-6a38', 'candidate-song-8607-8efe', 'candidate-song-738b-6dc7', 'candidate-song-767d-7389-87fe', 'candidate-song-5442-5927-81e8', 'candidate-song-694a-842c-91cc', 'candidate-song-6731-6dd1-771f', 'candidate-song-738b-5b89-77f3', 'candidate-song-8303-6210-5927', 'candidate-ming-5f90-968e', 'candidate-song-6b66-884d', 'candidate-ming-6731-4e4b-745c', 'candidate-ming-590f-5b8c-6df3', 'candidate-song-5b8b-b7-9673-8944', 'candidate-song-9673-8944', 'candidate-song-738b-742a', 'candidate-ming-5289-9438', 'candidate-ming-5289-6dd1', 'candidate-ming-738b-7aef-6dd1', 'candidate-ming-5468-74ca', 'candidate-ming-5433-742a', 'candidate-ming-8881-5f64-82b3', 'candidate-song-9ec3-5ead-5805', 'candidate-song-7fc1-5377', 'candidate-song-8d99-5e2b-79c0', 'candidate-song-5f90-7167'))
  GROUP BY poet_id
) sub
WHERE p.id = sub.poet_id;

